/** ------------------------------------------------------------------------------------------
 * 2. SHOWDOWN HP CURVE — `"Boss6HP"==d`, N.js:18211-18212, VERIFIED VERBATIM (byte-exact re-read
 * of the raw literal, not just the toolbox transcription):
 *
 *   Boss6HP = 135E12 * Math.pow(1.52, OptionsListAccount[369])
 *
 * *** CORRECTION vs the task brief / idleon-toolbox: the exponent base is 1.52, NOT 1.54. ***
 * idleon-toolbox's emperor.ts `getBossHp = (n) => 135e12 * Math.pow(1.54, n)` is WRONG (or stale
 * for an older patch) — the raw N.js literal reads unambiguously `Math.pow(1.52,...)`
 * (double-checked with two independent byte-offset reads spanning the line break at N.js:18211/
 * 18212, `135E12*\nMath.pow(1.52,...)`). Use 1.52 here.
 *
 * OptionsListAccount[369] = "highestEmperorShowdown", the account's cumulative Emperor win
 * count — VERIFIED as the increment target in `_customEvent_EmperorDed` (N.js:6988-6989,
 * the Emperor-defeated event handler, fires when `BossHP<=0` inside the fight scene):
 *   OptionsListAccount[369] = round(OptionsListAccount[369] + 1);
 *   QuestStatus.Potti7[0] = OptionsListAccount[369];   // quest tracker mirrors the same counter
 * The SAME index also drives the EMPEROR_BON_CYCLE walk in §1 — one counter, two consumers
 * (boss HP scaling AND the bonus-cycle accumulator), confirming why winning tougher showdowns
 * and unlocking more EmperorBon categories are the same progression axis.
 *
 * A player-facing "lower the current Showdown by one" DEBUG/GRIND button also exists (2-click
 * confirm via a `_GenINFO[25]` flag, N.js:21253, flavor text "Do_this_if_necessary_for_grinding_
 * boss_drops") that decrements [369] by 1 — a deliberate rewind for boss-drop farming, not part
 * of normal progression.
 *
 * USAGE NOTE (from idleon-toolbox's own pattern, worth carrying into a future "next showdown"
 * UI): the game previews the NEXT N showdowns' HP client-side as
 * `Array.from({length:6}, (_,i) => 135e12 * Math.pow(1.52, highestEmperorShowdown+i))` — with the
 * corrected 1.52 base.
 * ------------------------------------------------------------------------------------------ */
export function emperorBossHp(highestEmperorShowdown) {
  return 135e12 * Math.pow(1.52, highestEmperorShowdown);
}

/** ------------------------------------------------------------------------------------------
 * 3. ATTEMPT ECONOMY — three OptionsListAccount indices, all three dispatcher formulas VERIFIED
 * VERBATIM at N.js:18211-18212 (same wrapped statement as Boss6HP above); the SEMANTICS of [370]
 * (which the toolbox transcribes correctly as a formula but does not explain) were resolved by
 * finding both the daily-reset writer and the attempt-consumption writer in N.js, not just
 * restating the read-side formula.
 *
 * --- OptionsListAccount[369] — "highestEmperorShowdown" -------------------------------------
 * Cumulative Emperor win count. See §2 for the increment site. Read directly (no wrapper fn).
 *
 * --- OptionsListAccount[382] — feeds DailyEmperorTries and (x6) MaxEmperorAttemptStack --------
 *   `"DailyEmperorTries"==d` returns  round(1 + OptionsListAccount[382])              [VERIFIED]
 *   `"MaxEmperorAttemptStack"==d` returns
 *       round(5 + 5*Ninja("EmporiumBonus",39,0) + 6*OptionsListAccount[382])          [VERIFIED]
 * WHAT [382] ITSELF IS: UNVERIFIED — no direct `OptionsListAccount")[382]=` (or offset-computed
 * equivalent) assignment was found anywhere in N.js after a genuine search (exact-pattern grep
 * for the assignment, plus a scan of every standalone `382` token in the file for a plausible
 * setter — all other hits are unrelated: sprite/sound asset indices, unrelated `_UIinventory[382]`
 * UI-image slots, coordinate literals, etc.). It is READ only at the two sites above. Likely a
 * jade/gem-shop purchase count or similar persistent upgrade level, but the setter could not be
 * pinned down — treat [382]'s own VALUE as an external input (read from the save), while the two
 * formulas that consume it are confirmed byte-exact.
 * Ninja("EmporiumBonus",39,0) — VERIFIED, `"EmporiumBonus"==d` case, N.js:17972, verbatim:
 *   `Ninja[102][9].indexOf(Number2Letter[b]) != -1 ? 1 : 0`  — a 0/1 "is Jade Emporium row b
 *   purchased" flag, b=39 = the "Emperor_Season_Pass" row (na.JadeUpg id 39, N.js:23775,
 *   verbatim flavor text: "There_is_now_a_50%_chance_to_get_+2_visits_to_the_Emperor_every_day,_
 *   and_your_maximum_visits_goes_up_from_6_to_11"). Cross-check against the formulas: with
 *   [382]=0 and the pass NOT owned, MaxEmperorAttemptStack=round(5)=5 (displayed max = +1 = 6,
 *   see below); WITH the pass owned, =round(5+5)=10 (displayed = 11) — an exact match for the
 *   flavor text's "6 to 11". The "50% chance to get +2 visits" wording is a bit loose versus the
 *   actual daily-reset roll (see [370] below), which grants exactly +1 extra attempt (not +2) on
 *   a coin flip when the pass is owned — read as "some days you get 2 visits instead of 1
 *   baseline", not a literal +2 addend.
 *
 * --- OptionsListAccount[370] — "attempts consumed today" bank-debit counter -------------------
 * NOT a plain remaining-attempts count. Resolved by finding BOTH writers in N.js:
 *
 *  (a) ATTEMPT CONSUMPTION (fight button click), N.js:21322-21323 (`MenuType2==78` click
 *      handler, gated on `mouse within the Fight button bounds && OptionsListAccount[370] < 1`,
 *      i.e. only clickable while attempts remain), verbatim:
 *        OptionsListAccount[370] = round(OptionsListAccount[370] + 1);
 *      — every attempt (win OR loss) increments [370] by exactly 1, regardless of outcome.
 *
 *  (b) DAILY RESET (bank replenish), N.js:24980 (the big daily-rollover function alongside dozens
 *      of other OptionsListAccount[..]=0 resets), verbatim:
 *        if (round([370] - DailyEmperorTries) > -MaxEmperorAttemptStack)
 *          [370] = round([370] - DailyEmperorTries);
 *        if (randomInt(1,2)==1 && EmporiumBonus(39,0)==1 && round([370]-1) > -MaxEmperorAttemptStack)
 *          [370] = round([370] - 1);           // 50%-chance Emperor Season Pass bonus attempt
 *      — each day, [370] is DECREASED (made more negative) by DailyEmperorTries, floor-clamped so
 *      it never drops below -MaxEmperorAttemptStack (you cannot bank more than the max stack).
 *
 *  DISPLAY (N.js:21254, "Attempts_Left:" line):
 *        attemptsLeft = round(-1 * ([370] - 1)) = round(1 - [370])
 *        maxDisplayed  = round(MaxEmperorAttemptStack + 1)
 *  and separately (N.js:21253) `1==OptionsListAccount[370]` is special-cased to show
 *  "The_Emperor_is_not_accepting_new_challengers_until_tomorrow" — which is exactly the value at
 *  which attemptsLeft's own formula already evaluates to 0, so the branch is redundant-but-
 *  consistent flavor text, not a different threshold.
 *
 *  NET PICTURE: [370] is a signed debt counter, most negative right after a big daily replenish
 *  (banked attempts), climbing toward 0 and then to +1 as attempts get used; +1 is the hard
 *  ceiling (locked out, "come back tomorrow") enforced by the click handler's own guard
 *  (`[370] < 1` to even accept a click) working together with the daily-reset's floor clamp at
 *  -MaxEmperorAttemptStack (so unused attempts never accumulate past the stack cap either).
 *  attemptsLeft = max(0, round(1 - [370])) in practice (the game only ever nudges [370] by exactly
 *  ±1/±DailyEmperorTries through these two paths, so it never overshoots +1 on its own).
 * ------------------------------------------------------------------------------------------ */
export function dailyEmperorTries(optLacc382) {
  return Math.round(1 + optLacc382);
}

/** emporiumBonus39 = 1 if "Emperor_Season_Pass" (JadeUpg id 39) is purchased, else 0. */
export function maxEmperorAttemptStack(optLacc382, emporiumBonus39) {
  return Math.round(5 + 5 * emporiumBonus39 + 6 * optLacc382);
}

/** The value actually shown in the "Attempts_Left: X/Y" UI string (both sides get +1 vs. the raw
 *  dispatcher return — see N.js:21254). */
export function maxEmperorAttemptStackDisplayed(optLacc382, emporiumBonus39) {
  return maxEmperorAttemptStack(optLacc382, emporiumBonus39) + 1;
}

/** attempts remaining today, from the raw OptionsListAccount[370] bank-debit counter. */
export function emperorAttemptsLeft(optLacc370) {
  return Math.max(0, Math.round(1 - optLacc370));
}

